import React, { useState, useEffect, useRef } from 'react';
import axios from 'axios';
import FAWTable from '../FAWTable/FAWTable';
import FAWToast from '../FAWToast';

/**
 * QuestionnaireTable Component
 * 
 * Self-contained questionnaire table with built-in data fetching,
 * loading states, and error handling.
 * 
 * @param {Object} props
 * @param {string} props.agencyId - Agency ID for filtering questionnaires
 * @param {string} props.connectionName - Database connection name
 * @param {Function} props.onNavigate - Callback for navigation (row click)
 * @param {Function} props.onCopy - Callback for copy action
 * @param {Function} props.onEdit - Callback for edit action (optional)
 * @param {boolean} props.isEmbedded - Whether running in embedded mode
 */
/** localStorage key for persisting questionnaire list sort (aligns with legacy behaviour). */
const SORT_STORAGE_KEY = 'fawTable_sort_questionnaireTableAtlas';

const DEFAULT_SORT_MODEL = [{ field: 'name', sort: 'asc' }];

/** Load saved sort model from localStorage; validates shape and returns default if invalid. */
function loadSortModelFromStorage() {
    try {
        if (typeof window === 'undefined' || !window.localStorage) return DEFAULT_SORT_MODEL;
        const raw = window.localStorage.getItem(SORT_STORAGE_KEY);
        if (!raw) return DEFAULT_SORT_MODEL;
        const parsed = JSON.parse(raw);
        if (!Array.isArray(parsed) || parsed.length === 0) return DEFAULT_SORT_MODEL;
        const valid = parsed.every((item) => item && typeof item.field === 'string' && (item.sort === 'asc' || item.sort === 'desc'));
        return valid ? parsed : DEFAULT_SORT_MODEL;
    } catch {
        return DEFAULT_SORT_MODEL;
    }
}

const QuestionnaireTable = ({
    agencyId,
    connectionName,
    onNavigate,
    onCopy,
    onEdit,
    isEmbedded = false
}) => {
    const [data, setData] = useState([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState(null);
    const [toast, setToast] = useState({
        open: false,
        message: '',
        type: 'error'
    });

    // Persist sort in localStorage (aligns with legacy page cache behaviour)
    const [sortModel, setSortModel] = useState(loadSortModelFromStorage);

    const handleSortModelChange = (newModel) => {
        setSortModel(newModel);
        try {
            if (typeof window !== 'undefined' && window.localStorage) {
                window.localStorage.setItem(SORT_STORAGE_KEY, JSON.stringify(newModel || []));
            }
        } catch {
            // ignore
        }
    };

    const loadRequestIdRef = useRef(0);

    // Fetch questionnaire data on mount; cancel in-flight request on unmount or when deps change
    useEffect(() => {
        const controller = new AbortController();
        const requestId = (loadRequestIdRef.current += 1);

    const loadData = async () => {
        try {
            setLoading(true);
            setError(null);
            
            const response = await axios.get('/api/v1/questionnaire/list', {
                params: {
                    agencyId: agencyId,
                    connectionName: connectionName || ''
                    },
                    signal: controller.signal
            });

                if (requestId !== loadRequestIdRef.current) return;

            let result = [];
            if (response.data && response.data.data && Array.isArray(response.data.data)) {
                result = response.data.data;
            } else if (Array.isArray(response.data)) {
                result = response.data;
            } else {
                console.error("Unexpected response format:", response.data);
            }
            
            setData(result);
        } catch (err) {
                if (requestId !== loadRequestIdRef.current) return;
                if (axios.isCancel(err) || err?.name === 'AbortError' || err?.code === 'ERR_CANCELED') {
                    return;
                }
            console.error('QuestionnaireTable: Error loading data:', err);
            const errorMessage = err.response?.data?.error || err.message || 'Failed to load questionnaires';
            setError(errorMessage);
            setData([]);
            setToast({
                open: true,
                message: errorMessage,
                type: 'error'
            });
        } finally {
                if (requestId === loadRequestIdRef.current) {
            setLoading(false);
        }
            }
    };

        loadData();
        return () => controller.abort();
    }, [agencyId, connectionName]);

    const handleToastClose = () => {
        setToast(prev => ({ ...prev, open: false }));
    };

    const showToast = (message, type = 'warning') => {
        setToast({
            open: true,
            message: message,
            type: type
        });
    };

    // Table column configuration
    const columns = [
        {
            headerName: "Name",
            field: "name",
            flex: 2,
            minWidth: 200,
            maxWidth: 500,
            type: "link",
            sortable: true, // Explicitly enable sorting for this column
            hideable: false, // Lock this column - cannot be hidden
            disabled: (rowData) => rowData.isSync,
            disabledTooltip: "Cannot navigate while form is syncing. Please wait for sync to complete.",
            onClick: (params, e) => {
                if (e && typeof e.preventDefault === "function") {
                    e.preventDefault();
                }
                
                const rowData = params.row || params.data;
                
                // Prevent navigation if row is syncing
                if (rowData.isSync) {
                    showToast("Cannot navigate while form is syncing. Please wait for sync to complete.", "warning");
                    return;
                }
                
                const rowId = rowData.id;
                if (!rowId) {
                    showToast("No valid ID found for this row.", "error");
                    return;
                }
                
                // Call the navigation callback
                if (onNavigate) {
                    onNavigate(rowId, isEmbedded);
                }
            },
        },
        { 
            headerName: "Description", 
            field: "description", 
            flex: 2,
            minWidth: 200,
            maxWidth: 800
        },
        { 
            headerName: "Category", 
            field: "categoryMeaning", 
            flex: 0,
            width: 120,
            minWidth: 100
        },
        { 
            headerName: "Sub-Category", 
            field: "typeMeaning", 
            flex: 2,
            minWidth: 200,
            maxWidth: 600,
        },
        { 
            headerName: "Status", 
            field: "active", 
            type: "statusIndicator",
            flex: 0,
            width: 100,
            minWidth: 80,
            statusConfig: (value) => {
                // Handle boolean from database: true = has active version, false = no active version
                if (value === true) {
                    return { status: 'active', label: 'Active' };
                } else if (value === false) {
                    return { status: 'inactive', label: 'Inactive' };
                }
                return { status: 'info', label: String(value || '---') };
            },
            statusIndicatorProps: {
                size: 'small',
                showTooltip: false
            }
        }
    ];

    // Row actions configuration
    const actions = [
        {
            icon: 'clone',
            onClick: (rowData) => {
                if (rowData.isSync) {
                    showToast("Cannot copy while form is syncing. Please wait for sync to complete.", "warning");
                    return;
                }
                
                const id = rowData.id;
                if (!id) {
                    showToast("No valid ID found for this row.", "error");
                    return;
                }
                
                // Call the copy callback
                if (onCopy) {
                    onCopy(id, isEmbedded);
                }
            }
        }
    ];

    // Add edit action if callback is provided
    if (onEdit) {
        actions.push({
            icon: 'edit',
            onClick: (rowData) => {
                if (rowData.isSync) {
                    showToast("Cannot edit while form is syncing. Please wait for sync to complete.", "warning");
                    return;
                }
                
                const id = rowData.id;
                if (!id) {
                    showToast("No valid ID found for this row.", "error");
                    return;
                }
                
                onEdit(id, isEmbedded);
            }
        });
    }

    // Handle row styling for syncing rows
    const getRowClassName = (params) => {
        return (params.row && params.row.isSync) ? 'syncing-row' : '';
    };

    return (
        <>
            <FAWTable
                columns={columns}
                rows={data}
                actions={actions}
                loading={loading}
                showSearch={true}
                showFilter={true}
                showPagination={true}
                showToolbar={true}
                showColumns={true}
                showExport={true}
                autoHeight={true}
                emptyStateTitle={error || 'No questionnaires found.'}
                emptyStateMessage="Create your first questionnaire to get started."
                emptyStateNoResultsTitle="No matching questionnaires"
                emptyStateNoResultsMessage="Try adjusting your search terms or filters."
                getRowClassName={getRowClassName}
                sortModel={sortModel}
                onSortModelChange={handleSortModelChange}
                gridSx={{
                    '& .syncing-row': {
                        opacity: 0.5,
                        backgroundColor: '#f5f5f5',
                        cursor: 'not-allowed',
                    }
                }}
            />
            <FAWToast
                open={toast.open}
                message={toast.message}
                type={toast.type}
                duration={null}
                persistent={true}
                onClose={handleToastClose}
                position="top-right"
            />
        </>
    );
};

export default QuestionnaireTable;

